import{_ as n,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Release-Notizen: Versionsverlauf | Antigravity-Manager","description":"Erfahren Sie die Methoden zum Versionsverlauf von Antigravity-Manager. Bestätigen Sie Version und Updates auf der Settings-Seite, prüfen Sie Fixes und Hinweise im README-Changelog und validieren Sie die Upgradenützbarkeit mit /healthz.","frontmatter":{"title":"Release-Notizen: Versionsverlauf | Antigravity-Manager","sidebarTitle":"Versionen in 3 Minuten verstehen","subtitle":"Versionsverlauf: README-eingebetteter Changelog als Referenz","description":"Erfahren Sie die Methoden zum Versionsverlauf von Antigravity-Manager. Bestätigen Sie Version und Updates auf der Settings-Seite, prüfen Sie Fixes und Hinweise im README-Changelog und validieren Sie die Upgradenützbarkeit mit /healthz.","tags":["changelog","release","upgrade","troubleshooting"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":1},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"de/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}'),a={name:"de/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function s(d,e,o,l,u,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="versionsverlauf-readme-eingebetteter-changelog-als-referenz" tabindex="-1">Versionsverlauf: README-eingebetteter Changelog als Referenz <a class="header-anchor" href="#versionsverlauf-readme-eingebetteter-changelog-als-referenz" aria-label="Permalink to &quot;Versionsverlauf: README-eingebetteter Changelog als Referenz&quot;">​</a></h1><p>Sie bereiten sich vor, Antigravity Tools zu aktualisieren, und haben größte Angst nicht davor, &quot;nicht aktualisiert&quot; zu sein, sondern erst nach dem Update zu bemerken, dass es Kompatibilitätsänderungen gab. Auf dieser Seite wird die <strong>Lese-Methode des Antigravity Tools Changelogs (Versionsverlauf)</strong> klar erklärt, damit Sie vor dem Upgrade beurteilen können: Was wird dieses Update bei Ihnen beeinflussen?</p><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><ul><li>Auf der About-Seite in Settings schnell die aktuelle Version bestätigen, Updates prüfen und den Download-Einstieg erhalten</li><li>Im Changelog der README nur die Abschnitte lesen, die Sie betreffen (statt von Anfang bis Ende zu blättern)</li><li>Vor dem Upgrade eine Sache tun: Bestätigen, ob es Hinweise gibt, die &quot;Sie müssen manuell Konfiguration/Modell-Mapping ändern&quot; erfordern</li><li>Nach dem Upgrade einmal eine Mindestvalidierung (<code>/healthz</code>) durchführen, um zu bestätigen, dass der Proxy noch funktioniert</li></ul><h2 id="was-ist-ein-changelog" tabindex="-1">Was ist ein Changelog? <a class="header-anchor" href="#was-ist-ein-changelog" aria-label="Permalink to &quot;Was ist ein Changelog?&quot;">​</a></h2><p>Ein <strong>Changelog</strong> ist eine Liste, die pro Version aufzeichnet, &quot;was diesmal geändert wurde&quot;. Antigravity Tools schreibt es direkt in die README im Abschnitt &quot;Versionsverlauf&quot;, und jede Version wird mit Datum und wichtigen Änderungen gekennzeichnet. Vor dem Upgrade den Changelog zu lesen, kann die Wahrscheinlichkeit verringern, auf Kompatibilitätsänderungen oder Rückfallprobleme zu stoßen.</p><h2 id="wann-verwenden-sie-diese-seite" tabindex="-1">Wann verwenden Sie diese Seite <a class="header-anchor" href="#wann-verwenden-sie-diese-seite" aria-label="Permalink to &quot;Wann verwenden Sie diese Seite&quot;">​</a></h2><ul><li>Sie bereiten sich vor, von einer alten Version auf eine neue Version zu aktualisieren und möchten zuerst die Risikopunkte bestätigen</li><li>Sie stoßen auf ein Problem (z.B. 429/0 Token/Cloudflared) und möchten bestätigen, ob es in neueren Versionen behoben wurde</li><li>Sie pflegen eine einheitliche Version in Ihrem Team und benötigen eine Methode für Kollegen, &quot;Änderungen pro Version zu lesen&quot;</li></ul><h2 id="🎒-vorbereitung-vor-dem-start" tabindex="-1">🎒 Vorbereitung vor dem Start <a class="header-anchor" href="#🎒-vorbereitung-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitung vor dem Start&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Empfohlen, den Upgrade-Pfad zuerst vorzubereiten</p><p>Es gibt viele Installations-/Upgrade-Methoden (brew, manuelle Downloads von Releases, In-App-Updates). Wenn Sie noch nicht sicher sind, welchen Weg Sie wählen, schauen Sie zuerst auf <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/start/installation/">Installation und Upgrade: Beste Installationsmethode für Desktop (brew / releases)</a></strong>.</p></div><h2 id="machen-sie-mit" tabindex="-1">Machen Sie mit <a class="header-anchor" href="#machen-sie-mit" aria-label="Permalink to &quot;Machen Sie mit&quot;">​</a></h2><h3 id="schritt-1-bestatigen-sie-auf-der-about-seite-die-version-die-sie-derzeit-verwenden" tabindex="-1">Schritt 1: Bestätigen Sie auf der About-Seite die Version, die Sie derzeit verwenden <a class="header-anchor" href="#schritt-1-bestatigen-sie-auf-der-about-seite-die-version-die-sie-derzeit-verwenden" aria-label="Permalink to &quot;Schritt 1: Bestätigen Sie auf der About-Seite die Version, die Sie derzeit verwenden&quot;">​</a></h3><p><strong>Warum</strong> Der Changelog ist pro Version organisiert. Sie müssen zuerst Ihre aktuelle Version kennen, um zu wissen, &quot;wo Sie anfangen sollen zu lesen&quot;.</p><p>Pfad: <strong>Settings</strong> → <strong>About</strong>.</p><p><strong>Sie sollten sehen</strong>: Im Titelfeld der Seite werden der Anwendungsname und die Versionsnummer angezeigt (z.B. <code>v3.3.49</code>).</p><h3 id="schritt-2-klicken-sie-auf-update-prufen-und-erhalten-sie-die-neueste-version-und-den-download-einstieg" tabindex="-1">Schritt 2: Klicken Sie auf &quot;Update prüfen&quot; und erhalten Sie die neueste Version und den Download-Einstieg <a class="header-anchor" href="#schritt-2-klicken-sie-auf-update-prufen-und-erhalten-sie-die-neueste-version-und-den-download-einstieg" aria-label="Permalink to &quot;Schritt 2: Klicken Sie auf &quot;Update prüfen&quot; und erhalten Sie die neueste Version und den Download-Einstieg&quot;">​</a></h3><p><strong>Warum</strong> Sie müssen zuerst wissen, &quot;was die neueste Versionsnummer ist&quot;, um dann im Changelog die Versionsabschnitte auszuwählen, die Sie übersprungen haben.</p><p>Klicken Sie auf der About-Seite auf &quot;Update prüfen&quot;.</p><p><strong>Sie sollten sehen</strong>:</p><ul><li>Wenn ein Update verfügbar ist: Hinweis &quot;new version available&quot; und ein Download-Button erscheint (öffnet <code>download_url</code>)</li><li>Wenn bereits die neueste Version: Hinweis &quot;latest version&quot;</li></ul><h3 id="schritt-3-gehen-sie-zum-changelog-der-readme-und-lesen-sie-nur-die-versionen-die-sie-ubersprungen-haben" tabindex="-1">Schritt 3: Gehen Sie zum Changelog der README und lesen Sie nur die Versionen, die Sie übersprungen haben <a class="header-anchor" href="#schritt-3-gehen-sie-zum-changelog-der-readme-und-lesen-sie-nur-die-versionen-die-sie-ubersprungen-haben" aria-label="Permalink to &quot;Schritt 3: Gehen Sie zum Changelog der README und lesen Sie nur die Versionen, die Sie übersprungen haben&quot;">​</a></h3><p><strong>Warum</strong> Sie müssen sich nur um Änderungen zwischen &quot;von Ihrer aktuellen Version bis zur neuesten Version&quot; kümmern, andere historische Versionen können vorerst übersprungen werden.</p><p>Öffnen Sie die README, navigieren Sie zum <strong>&quot;Versionsverlauf (Changelog)&quot;</strong>, und lesen Sie ab der neuesten Version nach unten, bis Sie Ihre aktuelle Version sehen.</p><p><strong>Sie sollten sehen</strong>: Versionen im Format <code>vX.Y.Z (YYYY-MM-DD)</code> aufgelistet, und jede Version hat gruppierende Erklärungen (z.B. Kernfixes / Funktionsverbesserungen).</p><h3 id="schritt-4-machen-sie-nach-dem-upgrade-eine-mindestvalidierung" tabindex="-1">Schritt 4: Machen Sie nach dem Upgrade eine Mindestvalidierung <a class="header-anchor" href="#schritt-4-machen-sie-nach-dem-upgrade-eine-mindestvalidierung" aria-label="Permalink to &quot;Schritt 4: Machen Sie nach dem Upgrade eine Mindestvalidierung&quot;">​</a></h3><p><strong>Warum</strong> Die erste Sache nach dem Upgrade ist nicht &quot;komplexe Szenarien auszuführen&quot;, sondern zuerst zu bestätigen, dass der Proxy normal starten kann und von Clients aktivitätsgeprüft werden kann.</p><p>Führen Sie den Fluss aus <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Lokalen Reverse-Proxy starten und ersten Client anschließen (/healthz + SDK-Konfiguration)</a></strong> und validieren Sie mindestens einmal <code>GET /healthz</code>.</p><p><strong>Sie sollten sehen</strong>: <code>/healthz</code> gibt Erfolg zurück (zur Bestätigung der Dienstverfügbarkeit).</p><h2 id="zusammenfassung-neuerer-versionen-aus-readme" tabindex="-1">Zusammenfassung neuerer Versionen (aus README) <a class="header-anchor" href="#zusammenfassung-neuerer-versionen-aus-readme" aria-label="Permalink to &quot;Zusammenfassung neuerer Versionen (aus README)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Datum</th><th>Punkte, die Sie beachten sollten</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>Denkunterbrechung und 0-Token-Verteidigung; Entfernung von <code>gemini-2.5-flash-lite</code> und Hinweis zum manuellen Ersetzen benutzerdefinierter Mappings; Sprache/Theme-Einstellungen wirken sofort; Monitoring-Dashboard-Verbesserungen; OAuth-Kompatibilitätserhöhung</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Hintergrundprozess unter Windows läuft im Hintergrund (behebt Konsolenflackern)</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>Bildgenerierungsparameter-Mapping-Verbesserung (<code>size</code>/<code>quality</code>); Cloudflared-Tunnel-Unterstützung; Behebung von Startfehlern durch Merge-Konflikte; dreischichtige progressive Kontextkomprimierung</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Wie schnell beurteilen, ob dieses Update mich beeinflusst</p><p>Suchen Sie vorrangig nach zwei Arten von Sätzen:</p><ul><li><strong>Benutzerhinweise / Sie müssen ändern</strong>: Zum Beispiel explizit erwähnen, dass ein Standardmodell entfernt wurde und Sie angehalten werden, benutzerdefinierte Mappings manuell anzupassen</li><li><strong>Kernfixes / Kompatibilitätsfixes</strong>: Zum Beispiel Probleme wie 0 Token, 429, Windows-Flackern, Startfehler, die &quot;Sie daran hindern zu verwenden&quot;</li></ul></div><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Inhalt</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details>',34)])])}const m=n(a,[["render",s]]);export{c as __pageData,m as default};
